// === POLYFILL: fetch para n8n 2.x ===
const fetch = async (url, opts = {}) => {
  const method = (opts.method || 'GET').toUpperCase();
  const headers = opts.headers || {};
  let body = opts.body;
  let isJson = false;
  if (body && typeof body === 'string') {
    try { body = JSON.parse(body); isJson = true; } catch (e) {}
  } else if (body && typeof body === 'object') {
    isJson = true;
  }
  const response = await this.helpers.httpRequest({
    method, url, headers, body,
    json: isJson,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
  const bodyOut = response.body;
  return {
    ok: response.statusCode >= 200 && response.statusCode < 300,
    status: response.statusCode,
    json: async () => typeof bodyOut === 'string' ? JSON.parse(bodyOut) : bodyOut,
    text: async () => typeof bodyOut === 'string' ? bodyOut : JSON.stringify(bodyOut),
  };
};
// === END POLYFILL ===

const payload = $input.first().json.body || $input.first().json;
const lead_id = payload.lead_id;
const phone = payload.phone || payload.from;
const user_message = payload.message || payload.text || payload.body;

if (!lead_id && !phone) {
  throw new Error('lead_id ou phone obrigatório');
}

// Busca/cria lead
const h = { apikey: $vars.SUPABASE_ANON_KEY, Authorization: `Bearer ${$vars.SUPABASE_ANON_KEY}`, 'Content-Type': 'application/json' };
let lead;
if (lead_id) {
  const r = await fetch(`${$vars.SUPABASE_URL}/rest/v1/leads?id=eq.${lead_id}&select=*&limit=1`, { headers: h });
  const arr = r.ok ? await r.json() : [];
  lead = arr[0];
} else {
  const r = await fetch(`${$vars.SUPABASE_URL}/rest/v1/leads?phone=eq.${encodeURIComponent(phone)}&select=*&limit=1`, { headers: h });
  const arr = r.ok ? await r.json() : [];
  lead = arr[0];
  if (!lead) {
    // cria novo
    const cr = await fetch(`${$vars.SUPABASE_URL}/rest/v1/leads`, {
      method: 'POST',
      headers: { ...h, 'Prefer': 'return=representation' },
      body: JSON.stringify({ phone, stage: 'NOVO', status: 'active', created_at: new Date().toISOString() })
    });
    const carr = cr.ok ? await cr.json() : [];
    lead = carr[0];
  }
}

if (!lead) throw new Error('Não foi possível obter o lead');

// Mapeia stage -> agent_stage
const stageMap = {
  'NOVO': 'IA_NOVO',
  'EM_ATENDIMENTO': 'IA_ATENDIMENTO',
  'QUALIFICADO': 'IA_QUALIFICACAO',
  'AGENDADO': 'IA_AGENDADO',
  'FECHADO': 'IA_POSVENDA',
  'POS_VENDA': 'IA_POSVENDA',
  'FOLLOW_UP': 'IA_FOLLOWUP'
};
const agent_stage = stageMap[lead.stage] || 'IA_ATENDIMENTO';

return [{ json: { lead, user_message, agent_stage, client_id: lead.client_id || null } }];
